// Literal tiplərinin sintaksisi
let status: 'active' | 'inactive';
status = 'active';
console.log(status); // active
status = 'inactive';
console.log(status); // inactive
// status = 'pending'; // Xəta: 'pending' 'active' | 'inactive' tipinə təyin edilə bilməz

// String literal tipləri
type Direction = 'up' | 'down' | 'left' | 'right';
let move: Direction;
move = 'up';
console.log(move); // up
move = 'right';
console.log(move); // right
// move = 'diagonal'; // Xəta: 'diagonal' Direction tipinə təyin edilə bilməz

// Number literal tipləri
type DiceRoll = 1 | 2 | 3 | 4 | 5 | 6;
let roll: DiceRoll;
roll = 1;
console.log(roll); // 1
roll = 6;
console.log(roll); // 6
// roll = 7; // Xəta: 7 DiceRoll tipinə təyin edilə bilməz

// Boolean literal tipləri
type IsActive = true;
let isActive: IsActive;
isActive = true;
console.log(isActive); // true
// isActive = false; // Xəta: false IsActive tipinə təyin edilə bilməz

// Union tipləri ilə literal tiplər
type Status = 'success' | 'error' | 'pending';
let currentStatus: Status;
currentStatus = 'success';
console.log(currentStatus); // success
currentStatus = 'error';
console.log(currentStatus); // error
// currentStatus = 'failed'; // Xəta: 'failed' Status tipinə təyin edilə bilməz

// Obyektlərdə literal tiplər
interface User {
  role: 'admin' | 'user';
  name: string;
}

let user: User = {
  role: 'admin',
  name: 'Ali'
};

console.log(user); // { role: 'admin', name: 'Ali' }
// user.role = 'guest'; // Xəta: 'guest' 'admin' | 'user' tipinə təyin edilə bilməz

// Funksiyalarda literal tiplər
function setStatus(status: 'online' | 'offline'): string {
  return `Status set to: ${status}`;
}

console.log(setStatus('online')); // Status set to: online
console.log(setStatus('offline')); // Status set to: offline
// console.log(setStatus('away')); // Xəta: 'away' 'online' | 'offline' tipinə təyin edilə bilməz

// Praktik nümunə
type OrderStatus = 'pending' | 'shipped' | 'delivered';

interface Order {
  id: number;
  status: OrderStatus;
}

function getOrderInfo(order: Order): string {
  return `Order ${order.id} is ${order.status}`;
}

let order: Order = { id: 1, status: 'pending' };
console.log(getOrderInfo(order)); // Order 1 is pending
order.status = 'delivered';
console.log(getOrderInfo(order)); // Order 1 is delivered
// order.status = 'cancelled'; // Xəta: 'cancelled' OrderStatus tipinə təyin edilə bilməz

// Təhlükəsizlik nümunəsi
function processStatus(status: 'active' | 'inactive'): string {
  return `System is ${status}`;
}

console.log(processStatus('active')); // System is active
console.log(processStatus('inactive')); // System is inactive
// console.log(processStatus('pending')); // Xəta: 'pending' 'active' | 'inactive' tipinə təyin edilə bilməz

// Səhvə yol açan nümunə
let unsafe: any = 'active';
console.log(unsafe); // active
unsafe = 'pending';
console.log(unsafe); // pending, lakin tip təhlükəsizliyi yoxdur

// Düzgün yol
let safe: 'active' | 'inactive' = 'active';
console.log(safe); // active
// safe = 'pending'; // Xəta: 'pending' 'active' | 'inactive' tipinə təyin edilə bilməz

// Real layihə ssenarisi
type TrafficLight = 'red' | 'yellow' | 'green';

interface Signal {
  color: TrafficLight;
}

function showSignal(signal: Signal): string {
  return `Traffic light is ${signal.color}`;
}

let signal: Signal = { color: 'red' };
console.log(showSignal(signal)); // Traffic light is red
signal.color = 'green';
console.log(showSignal(signal)); // Traffic light is green
// signal.color = 'blue'; // Xəta: 'blue' TrafficLight tipinə təyin edilə bilməz

