let roll: DiceRoll;
roll = 1;
console.log(roll); // 1
roll = 6;
console.log(roll); // 6
// roll = 7; // Ошибка: 7 не может быть присвоен DiceRoll

// Булевы литеральные типы
type IsActive = true;
let isActive: IsActive;
isActive = true;
console.log(isActive); // true
// isActive = false; // Ошибка: false не может быть присвоен IsActive

